1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	};
17	
18	function basePremium(item: any): number {
19	  return BASE_PREMIUMS[item.type] ?? 0;
20	}
21	
22	export function claimOffice(input: any): unknown {
23	  const results = [];
24	  for (const step of input.steps) {
25	    validateItemTypes(step.items);
26	    let premium = PROCESSING_FEE;
27	    for (const item of step.items) {
28	      premium += basePremium(item);
29	    }
30	    results.push({ premium });
31	  }
32	  return { results };
33	}
34

